def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    term = np.sin(ratio * b / (a + 1)) * ((ratio - a) ** 7) / (a * b * 1.1 + 1)
                    priority += np.tanh(term) * (a + b) / 10
            priority += np.exp(ratio - 8) * np.sin(ratio * 2) ** 2
            if int(item * 2) % 7 == 0:
                priority *= 1.7
            else:
                priority /= 1.7
        elif 5 < ratio <= 8:
            for p in range(3, int(np.floor(ratio)) + 5):
                for q in range(1, p + 4):
                    val = ((ratio - p) ** 4) * np.cos(ratio * p * 1.2) / (q + 1)
                    priority += np.tanh(val) * 1.5
            priority += np.log1p(ratio) * 12 - np.sin(ratio - 5) * 3
            if bin_cap < item * 1.5:
                priority += np.sqrt(item / (bin_cap + 0.2)) * 3.3
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r + 1) * np.sin(r * ratio * 0.9)
            priority = np.cos(5 * ratio) * s + np.log(ratio) * -7 + np.tanh(3 * (5 - ratio)) * 2
            for m in range(1, 6):
                priority += np.sin(m * ratio * i) * ((ratio - 0.9) ** m) / (m + 1)
            if bin_cap > item * 2:
                priority -= np.exp(-ratio) * 6
        elif 1.2 <= ratio < 2:
            s = 0
            for n in range(2, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1)
            penalty = np.cos(15 * ratio) * 3 if bin_cap > item * 0.9 else np.sqrt(item / (bin_cap + 0.7)) * 5
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for k in range(1, 8):
                priority += np.sin(k * ratio * i * 0.5) * ((ratio - 0.5) ** k) / (k * 1.2)
        elif 0.5 <= ratio < 1.2:
            s = 0
            for x in range(1, 20):
                s += ((1.2 - ratio) ** x) / (x * 3.5)
            priority = s
            if (i * int(item * 2.3)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 3) + 1.5)
            for y in range(1, 10):
                priority += ((1.2 - ratio) ** y) * np.cos(y * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for z in range(1, 18):
                s += ((0.5 - ratio) ** z) / (z * 5) * np.cos(z * ratio * 3)
            priority = s + 1.5 / (bin_cap + 5)
            if int(item * 2.1) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 2.3) * 4
            for w in range(1, 10):
                priority += ((0.5 - ratio) ** w) / (w * 7) * np.sin(item * w * 1.3)
        else:
            s = 0
            for u in range(1, 15):
                s += ((0.2 - ratio) ** u) / (u * 8) * np.sin(u * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 4 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 5
            for v in range(1, 12):
                priority += ((0.2 - ratio) ** v) / (v * 9) * np.cos(item * v * 0.75)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.5) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.5) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        priorities[i] = priority
    return priorities
